sp_css.css:
/* ======================================================
   Emerald + Teal Modern UI
   ====================================================== */

body{
    background:#F4FBFA;
    font-family:"Inter","Segoe UI",sans-serif;
    color:#163B39;
}

/* Navbar */

.navbar{
    background:linear-gradient(90deg,#0F766E,#14B8A6)!important;
    border:none;
    box-shadow:0 8px 28px rgba(15,118,110,.18);
}

.navbar-brand{
    color:white!important;
    font-weight:700;
    font-size:20px;
}

.navbar-nav>li>a{
    color:white!important;
    font-weight:500;
}

.navbar-nav>li>a:hover{
    color:#CCFBF1!important;
}

/* Cards */

.panel,
.card{
    border:none;
    border-radius:18px;
    background:white;
    box-shadow:0 12px 32px rgba(0,0,0,.07);
    transition:.25s;
}

.panel:hover,
.card:hover{
    transform:translateY(-4px);
    box-shadow:0 18px 40px rgba(15,118,110,.15);
}

/* Buttons */

.btn{
    border-radius:12px;
    font-weight:600;
}

.btn-primary{
    background:linear-gradient(90deg,#0F766E,#14B8A6);
    border:none;
}

.btn-primary:hover{
    background:linear-gradient(90deg,#0B5D57,#0F766E);
}

/* Forms */

.form-control{
    border-radius:12px;
    border:1px solid #C7E7E4;
    box-shadow:none;
}

.form-control:focus{
    border-color:#14B8A6;
    box-shadow:0 0 0 4px rgba(20,184,166,.18);
}

/* Tables */

.table{
    background:white;
    border-radius:16px;
    overflow:hidden;
}

.table>thead{
    background:#ECFDFC;
    color:#0F766E;
    font-weight:600;
}

/* Panel Heading */

.panel-heading{
    background:white!important;
    border-bottom:1px solid #E5F3F2;
    font-weight:600;
}

/* Badges */

.badge{
    border-radius:20px;
    padding:7px 14px;
}

/* Links */

a{
    color:#0F766E;
}

a:hover{
    color:#0B5D57;
    text-decoration:none;
}

/* Titles */

h1,h2,h3,h4,h5{
    color:#163B39;
    font-weight:700;
}

/* Inputs */

input,
select,
textarea{
    transition:.25s;
}

/* Icons */

.fa{
    color:#14B8A6;
}

/* KPI */

.kpi-value{
    color:#0F766E;
    font-weight:700;
}
